import * as React from 'react';
import { Container, Typography, Box, Button, Paper } from '@mui/material';
import { Link } from 'react-router-dom';

export default function Home() {
  return (
    <Container maxWidth="md" sx={{mt:6}}>
      <Paper elevation={3} sx={{p:4, textAlign: 'center'}}>
        <Typography variant="h3" gutterBottom>Diễn đàn hỏi-đáp sinh viên</Typography>
        <Typography variant="h6" color="text.secondary" gutterBottom>
          Chào mừng bạn đến với diễn đàn hỏi-đáp dành cho sinh viên!
        </Typography>
        <Box sx={{mt:4, display:'flex', justifyContent:'center', gap:2}}>
          <Button variant="contained" color="primary" component={Link} to="/questions">Xem câu hỏi</Button>
          <Button variant="outlined" color="primary" component={Link} to="/login">Đăng nhập</Button>
          <Button variant="outlined" color="secondary" component={Link} to="/register">Đăng ký</Button>
        </Box>
      </Paper>
    </Container>
  );
}
